class RedisConnectionManager:
    def __init__(self, 
                 connection_type: str = 'cluster',
                 hosts: List[Dict[str, Any]] = None,
                 password: Optional[str] = None,
                 ssl: bool = True,
                 ssl_cert_reqs: str = 'required',
                 ssl_ca_certs: Optional[str] = None):
        self.connection_type = connection_type
        self.hosts = hosts or []
        self.password = password
        self.ssl = ssl
        self.ssl_cert_reqs = ssl_cert_reqs
        self.ssl_ca_certs = ssl_ca_certs
        self.client = None
        
    def connect_cluster(self):
        startup_nodes = [
            {"host": node['host'], "port": node.get('port', 6379)}
            for node in self.hosts
        ]
        
        self.client = RedisCluster(
            startup_nodes=startup_nodes,
            password=self.password,
            decode_responses=True,
            ssl=self.ssl,
            ssl_cert_reqs=self.ssl_cert_reqs,
            ssl_ca_certs=self.ssl_ca_certs,
            skip_full_coverage_check=True
        )
        logger.info("Connected to Redis Cluster")
        return self.client
    
    def connect_sentinel(self, service_name: str = 'mymaster'):
        sentinel_hosts = [
            (node['host'], node.get('port', 26379))
            for node in self.hosts
        ]
        
        sentinel = Sentinel(
            sentinel_hosts,
            socket_timeout=0.5,
            password=self.password,
            ssl=self.ssl,
            ssl_cert_reqs=self.ssl_cert_reqs,
            ssl_ca_certs=self.ssl_ca_certs
        )
        
        self.client = sentinel.master_for(
            service_name,
            socket_timeout=0.5,
            password=self.password,
            decode_responses=True
        )
        logger.info("Connected to Redis via Sentinel")
        return self.client
    
    def connect_standalone(self):
        if not self.hosts:
            raise ValueError("No host specified for standalone connection")
        
        host_config = self.hosts[0]
        self.client = redis.Redis(
            host=host_config['host'],
            port=host_config.get('port', 6379),
            password=self.password,
            decode_responses=True,
            ssl=self.ssl,
            ssl_cert_reqs=self.ssl_cert_reqs,
            ssl_ca_certs=self.ssl_ca_certs
        )
        logger.info("Connected to Redis Standalone")
        return self.client
    
    def get_client(self, service_name: str = 'mymaster'):
        if self.client:
            return self.client
            
        if self.connection_type == 'cluster':
            return self.connect_cluster()
        elif self.connection_type == 'sentinel':
            return self.connect_sentinel(service_name)
        elif self.connection_type == 'standalone':
            return self.connect_standalone()
        else:
            raise ValueError(f"Unknown connection type: {self.connection_type}")


class SecureCache:
    def __init__(self, redis_client: redis.Redis, encryption_key: Optional[str] = None):
        self.redis = redis_client
        self.encryption_key = encryption_key or os.getenv('CACHE_ENCRYPTION_KEY', secrets.token_hex(32))
        
    def _hash_key(self, key: str) -> str:
        return hashlib.sha256(f"{key}{self.encryption_key}".encode()).hexdigest()
    
    def _encrypt_value(self, value: str) -> str:
        try:
            from cryptography.fernet import Fernet
            key = hashlib.sha256(self.encryption_key.encode()).digest()
            key_b64 = base64.urlsafe_b64encode(key)
            f = Fernet(key_b64)
            return f.encrypt(value.encode()).decode()
        except ImportError:
            logger.warning("cryptography library not available, storing unencrypted")
            return value
    
    def _decrypt_value(self, encrypted_value: str) -> str:
        try:
            from cryptography.fernet import Fernet
            import base64
            key = hashlib.sha256(self.encryption_key.encode()).digest()
            key_b64 = base64.urlsafe_b64encode(key)
            f = Fernet(key_b64)
            return f.decrypt(encrypted_value.encode()).decode()
        except ImportError:
            return encrypted_value
        except Exception as e:
            logger.error(f"Decryption failed: {e}")
            return None
    
    def set_with_ttl(self, key: str, value: Any, ttl_seconds: int, encrypt: bool = False):
        try:
            hashed_key = self._hash_key(key)
            
            if isinstance(value, (dict, list)):
                value = json.dumps(value)
            else:
                value = str(value)
            
            if encrypt:
                value = self._encrypt_value(value)
            
            self.redis.setex(hashed_key, ttl_seconds, value)
            logger.info(f"Stored key with TTL: {ttl_seconds}s")
            return True
        except Exception as e:
            logger.error(f"Error setting cache: {e}")
            return False
    
    def get(self, key: str, encrypted: bool = False) -> Optional[str]:
        try:
            hashed_key = self._hash_key(key)
            value = self.redis.get(hashed_key)
            
            if value is None:
                return None
            
            if encrypted:
                value = self._decrypt_value(value)
            
            try:
                return json.loads(value)
            except (json.JSONDecodeError, TypeError):
                return value
        except Exception as e:
            logger.error(f"Error getting cache: {e}")
            return None
    
    def delete(self, key: str) -> bool:
        try:
            hashed_key = self._hash_key(key)
            self.redis.delete(hashed_key)
            return True
        except Exception as e:
            logger.error(f"Error deleting cache: {e}")
            return False
    
    def exists(self, key: str) -> bool:
        try:
            hashed_key = self._hash_key(key)
            return self.redis.exists(hashed_key) > 0
        except Exception as e:
            logger.error(f"Error checking existence: {e}")
            return False


class SessionManager:
    def __init__(self, cache: SecureCache):
        self.cache = cache
        self.session_ttl = int(os.getenv('SESSION_TTL', 3600))
    
    def create_session(self, user_id: str, metadata: Optional[Dict] = None) -> str:
        session_token = secrets.token_urlsafe(32)
        session_data = {
            'user_id': user_id,
            'created_at': str(timedelta(seconds=0)),
            'metadata': metadata or {}
        }
        
        key = f"session:{session_token}"
        self.cache.set_with_ttl(key, session_data, self.session_ttl, encrypt=True)
        logger.info(f"Created session for user: {user_id}")
        return session_token
    
    def get_session(self, session_token: str) -> Optional[Dict]:
        key = f"session:{session_token}"
        return self.cache.get(key, encrypted=True)
    
    def invalidate_session(self, session_token: str) -> bool:
        key = f"session:{session_token}"
        return self.cache.delete(key)
    
    def refresh_session(self, session_token: str) -> bool:
        session_data = self.get_session(session_token)
        if not session_data:
            return False
        
        key = f"session:{session_token}"
        return self.cache.set_with_ttl(key, session_data, self.session_ttl, encrypt=True)


