class RateLimiter:
    def __init__(self, cache: SecureCache):
        self.cache = cache
    
    def check_rate_limit(self, identifier: str, max_requests: int, window_seconds: int) -> bool:
        key = f"ratelimit:{identifier}"
        
        try:
            current = self.cache.redis.get(self.cache._hash_key(key))
            
            if current is None:
                self.cache.set_with_ttl(key, 1, window_seconds)
                return True
            
            current_count = int(current)
            
            if current_count >= max_requests:
                return False
            
            self.cache.redis.incr(self.cache._hash_key(key))
            return True
        except Exception as e:
            logger.error(f"Rate limit check error: {e}")
            return True


